import React from 'react';
import { useTranslation } from 'react-i18next';
import { DollarSign, ShieldCheck, Plus, ArrowUpRight } from 'lucide-react';
import { formatCurrency } from '../../utils/currency';
import '../../styles/BalanceCard.css';

/**
 * BalanceCard Component
 * Displays wallet balance with action buttons
 * 
 * @param {Object} props
 * @param {number} props.balance - Current wallet balance
 * @param {string} props.currency - Currency code (USD, EUR, etc.)
 * @param {number} props.availableBalance - Available balance for transactions
 * @param {number} props.pendingBalance - Pending transactions amount
 * @param {boolean} props.isVerified - Account verification status
 * @param {function} props.onAddFunds - Callback for add funds button
 * @param {function} props.onWithdraw - Callback for withdraw button
 * @param {boolean} props.canWithdraw - Whether withdrawal is allowed
 * @param {boolean} props.loading - Loading state for buttons
 */
export default function BalanceCard({
  balance = 0,
  currency = 'USD',
  availableBalance = 0,
  pendingBalance = 0,
  isVerified = false,
  onAddFunds,
  onWithdraw,
  canWithdraw = false,
  loading = false
}) {
  const { t } = useTranslation();

  return (
    <div className="balance-card">
      {/* Card Header */}
      <div className="balance-card-header">
        <div className="balance-title-wrapper">
          <span className="balance-label">{t('wallet.availableBalance')}</span>
          {isVerified && (
            <span className="balance-badge verified">
              <ShieldCheck size={12} />
              {t('wallet.verified')}
            </span>
          )}
        </div>
      </div>

      {/* Balance Amount */}
      <div className="balance-amount-wrapper">
        <DollarSign size={32} className="currency-symbol" />
        <span className="balance-amount">
          {formatCurrency(balance, currency)}
        </span>
        <span className="currency-code">{currency}</span>
      </div>

      {/* Balance Details */}
      {(availableBalance !== balance || pendingBalance > 0) && (
        <div className="balance-details">
          {availableBalance !== balance && (
            <div className="balance-detail-row">
              <span className="detail-label">{t('wallet.available')}</span>
              <span className="detail-value">
                {formatCurrency(availableBalance, currency)}
              </span>
            </div>
          )}
          {pendingBalance > 0 && (
            <div className="balance-detail-row pending">
              <span className="detail-label">{t('wallet.pending')}</span>
              <span className="detail-value">
                {formatCurrency(pendingBalance, currency)}
              </span>
            </div>
          )}
        </div>
      )}

      {/* Action Buttons */}
      <div className="balance-actions">
        <button
          type="button"
          className="btn-balance btn-add-funds"
          onClick={onAddFunds}
          disabled={loading}
          aria-label={t('wallet.addFunds')}
        >
          <Plus size={18} />
          <span>{t('wallet.addFunds')}</span>
        </button>
        
        <button
          type="button"
          className="btn-balance btn-withdraw"
          onClick={onWithdraw}
          disabled={loading || !canWithdraw}
          aria-label={t('wallet.withdraw')}
        >
          <ArrowUpRight size={18} />
          <span>{t('wallet.withdraw')}</span>
        </button>
      </div>

      {/* Last Updated */}
      <div className="balance-footer">
        <span className="last-updated">
          {t('wallet.lastUpdated')}: {new Date().toLocaleTimeString()}
        </span>
      </div>
    </div>
  );
}
